          if(snap.roce&&snap.roce.value)returns.push({l:"ROCE",v:snap.roce.value,numVal:snap.roce.numVal,sp500:13,tip:"Return on capital employed — S&P 500 avg ~13%",isGood:parseFloat(snap.roce.value)>=12});
